class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        long maxScore = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int[] subarray = Arrays.copyOfRange(nums, i, j + 1);
                long score = calculateScore(subarray);
                maxScore = Math.max(maxScore, score);
            }
        }
        return maxScore;
    }
    private long calculateScore(int[] subarray) {
        int gcd = subarray[0];
        for (int i = 1; i < subarray.length; i++) {
            gcd = gcd(gcd, subarray[i]);
        }
        return (long) subarray.length * gcd;
    }
    private int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
